// encodeMultipart builds the DisputeEvidenceCreation multipart/form-data body.
func (r *DisputeEvidenceCreation) encodeMultipart() (io.Reader, string, error) {
	var body bytes.Buffer
	w := multipart.NewWriter(&body)
	if r != nil {
		if r.File != nil {
			part, err := w.CreateFormFile("file", "file")
			if err != nil {
				return nil, "", err
			}
			if _, err := io.Copy(part, r.File); err != nil {
				return nil, "", err
			}
		}
	}
	if err := w.Close(); err != nil {
		return nil, "", err
	}
	return &body, w.FormDataContentType(), nil
}

