// Environment environment object, indicating in which environment the payment was made.
//
// :::caution
// Only required if `initiator: customer`.
// :::
//
// :::note
// Only `browser` is available at the moment.
// :::
// Variants:
//   - browser → BrowserEnvironment
type Environment interface {
	isEnvironment()
}

// decodeEnvironment reads the "type" discriminator and decodes into the
// matching variant.
func decodeEnvironment(data []byte) (Environment, error) {
	var tag struct {
		T string `json:"type"`
	}
	if err := json.Unmarshal(data, &tag); err != nil {
		return nil, err
	}
	switch tag.T {
	case "browser":
		var out BrowserEnvironment
		if err := json.Unmarshal(data, &out); err != nil {
			return nil, err
		}
		return out, nil
	}
	return nil, fmt.Errorf("unknown Environment tag: %q", tag.T)
}

